import UIKit

class UniversalLinkHandler {
    static func handleUniversalLink(_ url: URL, completion: @escaping (String?) -> Void) {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false),
              let queryItems = components.queryItems else {
            completion(nil)
            return
        }
        
        for item in queryItems where item.name == "token" {
            completion(item.value)
            return
        }
        
        completion(nil)
    }
}

@UIApplicationMain
class AppDelegate: UIResponder, UIApplicationDelegate {

    var window: UIWindow?

    func application(_ application: UIApplication, continue userActivity: NSUserActivity, restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        if userActivity.activityType == NSUserActivityTypeBrowsingWeb,
           let incomingURL = userActivity.webpageURL {
            
            UniversalLinkHandler.handleUniversalLink(incomingURL) { token in
                DispatchQueue.main.async {
                    guard let token = token else {
                        return
                    }
                    
                    let storyboard = UIStoryboard(name: "Main", bundle: nil)
                    if let resetPasswordViewController = storyboard.instantiateViewController(withIdentifier: "ResetPasswordViewController") as? ResetPasswordViewController {
                        resetPasswordViewController.token = token
                        
                        self.window?.rootViewController = resetPasswordViewController
